# Future Work

## Carcass Sharing Implementation

Next commit will implement `stage_carcass_sharing()` in the tick pipeline:

```rust
fn stage_carcass_sharing(&mut self) {
    for (victim_pos, victim_age) in recently_dead_agents {
        let neighbors = self.index.query_radius(victim_pos, self.config.carcass_distribution_radius);
        let maturity = (victim_age as f32 / self.config.carcass_maturity_age as f32).min(1.0);
        let count = neighbors.len() as f32;
        let normalization = count.powf(self.config.carcass_neighbor_exponent);

        let health_each = (self.config.carcass_health_reward * maturity) / normalization;
        let energy_each = health_each * self.config.carcass_energy_share_rate;
        let repro_each = (self.config.carcass_reproduction_reward * maturity) / normalization;

